  ('fire-eq-tech-moex-01626', 'fire-eq-tech', 'fire-eq-tech-moex-105-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '開放式撒水頭進行放水試驗，撒水頭口徑11.3mm放水壓力為1kgf/cm2時，放水量為50L/min，若放水 壓力增為2kgf/cm2時，其放水量約為多少L/min？', '["50", "70", "90", "120"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "9d6ee73c516d", "answer_pdf_sha1": "2479cea3f32f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0810", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
