  ('fire-eq-tech-moex-01628', 'fire-eq-tech', 'fire-eq-tech-moex-105-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '竣工查驗一進口汽車修理廠，所採用移動式泡沫滅火設備作為滅火設備，預計設置三個泡沫消防栓箱， 選用之泡沫原液為百分之六的水成膜泡沫，則現場泡沫原液儲槽內至少應存放多少公升的泡沫原液儲存 量，方可符合規定：', '["120公升", "180公升", "225公升", "300公升"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "9d6ee73c516d", "answer_pdf_sha1": "2479cea3f32f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0810", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 21, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
